solution_code:
#include <iostream>
#include <string>
#include <string_view>

enum class Rarity
{
    Common    = 0,
    Rare      = 1,
    Legendary = 2
};

struct Item
{
    std::string name;
    int         quantity;
    Rarity      rarity;
};

std::string_view rarityLabel(Rarity r)
{
    switch (r)
    {
        case Rarity::Common:    return "Common";
        case Rarity::Rare:      return "Rare";
        case Rarity::Legendary: return "Legendary";
        default:                return "Unknown";
    }
}

int main()
{
    int n{};
    std::cin >> n;

    int total{ 0 };
    for (int i{ 0 }; i < n; ++i)
    {
        std::string name;
        int quantity{};
        int code{};
        std::cin >> name >> quantity >> code;
        Item item{ name, quantity, static_cast<Rarity>(code) };

        std::cout << item.name << " x" << item.quantity
                  << " [" << rarityLabel(item.rarity) << "]\n";
        total += item.quantity;
    }

    std::cout << '\n';
    std::cout << "Total items: " << total << '\n';

    return 0;
}

