solution_code:
#include <iostream>

template <typename T>
struct Pair
{
    T first;
    T second;
};

template <typename T>
T larger(const Pair<T>& p)
{
    if (p.first >= p.second)
        return p.first;
    return p.second;
}

int main()
{
    int a1{}, b1{}, a2{}, b2{};
    double d1{}, d2{};
    std::cin >> a1 >> b1 >> a2 >> b2 >> d1 >> d2;

    Pair<int> p1{ a1, b1 };
    Pair<int> p2{ a2, b2 };
    Pair p3{ d1, d2 };

    std::cout << "Int pair 1 max: " << larger(p1) << '\n';
    std::cout << "Int pair 2 max: " << larger(p2) << '\n';
    std::cout << "Double pair max: " << larger(p3) << '\n';

    return 0;
}
